import React from 'react';
import { motion } from 'framer-motion';
import '../css/Home.css';

const Home = () => {
    return (
        <div className="Home">

            <motion.h1 initial={{ x: "1rem", y: "-100rem" }}
                animate={{ color: 'rgb(250,200,0)', x: "1rem", y: "1rem" }}
                transition={{ delay: .2, type: 'spring', stiffness: 500 }}
            >
                Welcome to My Home!
            </motion.h1>
            <div>
                <motion.h2
                    initial={{ x: "-100rem", y: "3rem" }}
                    animate={{ color: 'rgb(250,200,0)', x: "4rem", y: "3rem" }}
                    transition={{ delay: .8, type: 'spring', stiffness: 500 }}
                >My Name is Hyuil!</motion.h2>
                <img src="/img/hyuil.jpg" alter="hyuil" />
            </div>
        </div >
    );
};

export default Home;