import Blog from '../components/Blog';
import Movie from '../components/Movie';
import Home from '../components/Home';
import About from '../components/About';
import Donot from '../components/Donot';
import Sketch from '../components/sketch';
import { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import Face from '../components/Face';
import '../css/Main.css';

const Main = () => {
    const [navIndex, setNavIndex] = useState(0);

    const menuList = {
        0: <Home />,
        1: <Blog />,
        2: <About />,
        3: <Movie />,
        4: <Donot />,
    }
    const toggle = useRef(null);

    return (
        <div className="Main">

            <motion.nav className="top-nav" initial={{ x: -400 }} animate={{ x: 0 }}>
                <Face />
                <input ref={toggle} id="menu-toggle" style={{ "visibility": "hidden" }} type="checkbox" />
                <label className='menu-button-container' htmlFor="menu-toggle">
                    <div className='menu-button'></div>
                </label>

                <ul className="menu">
                    <li onClick={() => { setNavIndex(0); toggle.current.checked = false; }}>Home</li>
                    <li onClick={() => { setNavIndex(1); toggle.current.checked = false; }}>Blog</li>
                    <li onClick={() => { setNavIndex(2); toggle.current.checked = false; }}>About</li>
                    <li onClick={() => { setNavIndex(3); toggle.current.checked = false; }}>Movie</li>
                    <li onClick={() => { setNavIndex(4); toggle.current.checked = false; }} style={{ 'color': 'red' }}>DO NOT CLICK ME!</li>
                </ul>

            </motion.nav>
            <div className="link">
                <p>CopyRight &copy; mailhyuil@gmail.com <a href="https://www.youtube.com/LameRhino3d"><i className="xi-youtube xi-2x"></i></a></p>
            </div>

            <section>
                {menuList[navIndex]}
            </section>
        </div>
    );
}

export default Main;