import React from 'react';
import { motion } from 'framer-motion';
import '../css/About.css';
const About = () => {
    return (
        <div className="About">
            <motion.h1 style={{ fontSize: "2rem", color: "white", display: "inline-block" }}
                initial={{ x: -100, y: -100 }}
                animate={{ color: 'rgb(250,200,0)', x: 10, y: 10 }}
                transition={{ delay: .2, type: 'spring', stiffness: 500 }}>
                About me...
            </motion.h1>
        </div>
    );
};

export default About;